# Convert to mutable grid and pad to uniform width
grid = [list(line) for line in chunk]
max_len = max(len(row) for row in grid)
for row in grid:
    row += [' '] * (max_len - len(row))

rows, cols = len(grid), max_len

def place_filament(length):
    """Perform a random walk and mark 'W' along its path."""
    r, c = random.randrange(rows), random.randrange(cols)
    for _ in range(length):
        if grid[r][c] == ' ':
            grid[r][c] = 'W'
        dr, dc = random.choice([(1,0),(-1,0),(0,1),(0,-1)])
        r = max(0, min(rows-1, r+dr))
        c = max(0, min(cols-1, c+dc))

# Create multiple filament structures
for _ in range(10):
    place_filament(random.randint(10, 20))

# Add some random isolated Ws
for _ in range(200):
    r, c = random.randrange(rows), random.randrange(cols)
    if grid[r][c] == ' ':
        grid[r][c] = 'W'

# Print the resulting grid
for row in grid:
    print('"' + ''.join(row) + "\",")


